import neopixel
import machine
import time

class NeoPro:
    def __init__(self, pin, num):
        self.np = neopixel.NeoPixel(machine.Pin(pin), num)
        self.num = num

    def set_color(self, i, r, g, b):
        self.np[i] = (r, g, b)
        self.np.write()

    def rainbow_cycle(self, wait):
        for j in range(255):
            for i in range(self.num):
                rc_index = (i * 256 // self.num) + j
                self.np[i] = self.wheel(rc_index & 255)
            self.np.write()
            time.sleep(wait)

    def wheel(self, pos):
        if pos < 85:
            return (pos * 3, 255 - pos * 3, 0)
        elif pos < 170:
            pos -= 85
            return (255 - pos * 3, 0, pos * 3)
        else:
            pos -= 170
            return (0, pos * 3, 255 - pos * 3)
